import{c as a,Q as t,j as n,m as i}from"./chunks/framework.CBiVa4O3.js";const u=JSON.parse('{"title":"预训练、SFT 与 RLHF:一个 LLM 是怎么被训出来的","description":"","frontmatter":{},"headers":[],"relativePath":"../aiLearning/17-预训练SFT与RLHF.md","filePath":"../aiLearning/17-预训练SFT与RLHF.md","lastUpdated":1778496697000}'),e={name:"../aiLearning/17-预训练SFT与RLHF.md"};function p(l,s,o,h,r,d){return t(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="预训练、sft-与-rlhf-一个-llm-是怎么被训出来的" tabindex="-1">预训练、SFT 与 RLHF:一个 LLM 是怎么被训出来的 <a class="header-anchor" href="#预训练、sft-与-rlhf-一个-llm-是怎么被训出来的" aria-label="Permalink to &quot;预训练、SFT 与 RLHF:一个 LLM 是怎么被训出来的&quot;">​</a></h1><p>很多人以为&quot;GPT 就是用海量数据训练出来的&quot;。这话不算错,但漏了关键的一半:<strong>只做 pre-training 你得到的不是 ChatGPT,而是一个会胡言乱语的鹦鹉</strong>。从鹦鹉到助手,中间有几道关键工序。</p><blockquote><p>一句话先记住:<strong>Pre-training 决定模型&quot;会什么&quot;,SFT 决定模型&quot;听不听话&quot;,RLHF 决定模型&quot;懂不懂分寸&quot;</strong>。</p></blockquote><hr><h2 id="一、llm-的三阶段-pre-training-→-sft-→-rlhf-dpo" tabindex="-1">一、LLM 的三阶段(Pre-training → SFT → RLHF/DPO) <a class="header-anchor" href="#一、llm-的三阶段-pre-training-→-sft-→-rlhf-dpo" aria-label="Permalink to &quot;一、LLM 的三阶段(Pre-training → SFT → RLHF/DPO)&quot;">​</a></h2><p>整体流程长这样:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始 LLM 训练管线</span></span>
<span class="line"><span>─────────────────────────────────────────────────</span></span>
<span class="line"><span>[1] Pre-training (预训练)</span></span>
<span class="line"><span>    数据:全网爬下来的 10T+ token(代码、网页、书、论文)</span></span>
<span class="line"><span>    目标:next token prediction</span></span>
<span class="line"><span>    产出:一个&quot;什么都见过、什么都会接半句&quot;的 base model</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>[2] SFT (Supervised Fine-Tuning,指令微调)</span></span>
<span class="line"><span>    数据:几万到几百万条&quot;指令-回答&quot;对(人写的)</span></span>
<span class="line"><span>    目标:学会&quot;被问到该怎么回答&quot;</span></span>
<span class="line"><span>    产出:一个会&quot;听懂人话&quot;的 instruct model</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>[3] RLHF / DPO (对齐)</span></span>
<span class="line"><span>    数据:人类偏好排序(同一问题的多个答案,A 比 B 好)</span></span>
<span class="line"><span>    目标:学会&quot;什么样的回答让人满意&quot;</span></span>
<span class="line"><span>    产出:ChatGPT / Claude 这种能直接用的助手</span></span></code></pre></div><p>每一步的角色:</p><table tabindex="0"><thead><tr><th>阶段</th><th>解决的问题</th><th>数据规模</th><th>算力占比</th></tr></thead><tbody><tr><td>Pre-training</td><td>让模型&quot;见多识广&quot;</td><td>TB 级 token</td><td>~99%</td></tr><tr><td>SFT</td><td>让模型&quot;懂指令格式&quot;</td><td>几万 ~ 几百万样本</td><td>~0.5%</td></tr><tr><td>RLHF/DPO</td><td>让模型&quot;贴合人类偏好&quot;</td><td>几万到几十万对比对</td><td>~0.5%</td></tr></tbody></table><blockquote><p>预训练吃掉绝大多数算力,但<strong>对最终用户体验影响最大的反而是后两步</strong>。这就是为什么&quot;参数量相近的模型,体验差距能很大&quot;。</p></blockquote><hr><h2 id="二、pre-training-海量-next-token-prediction" tabindex="-1">二、Pre-training:海量 next token prediction <a class="header-anchor" href="#二、pre-training-海量-next-token-prediction" aria-label="Permalink to &quot;二、Pre-training:海量 next token prediction&quot;">​</a></h2><p>目标只有一个:给前 N 个 token,预测第 N+1 个。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入:&quot;The quick brown fox jumps over the&quot;</span></span>
<span class="line"><span>目标:&quot;lazy&quot;</span></span>
<span class="line"><span>loss: -log P(lazy | The quick brown fox jumps over the)</span></span></code></pre></div><p>每一条训练样本就这么一回事,扫几万亿次,模型就把语言、世界知识、代码、推理逻辑全压进权重里。</p><h3 id="数据-规模你得有点感觉" tabindex="-1">数据(规模你得有点感觉) <a class="header-anchor" href="#数据-规模你得有点感觉" aria-label="Permalink to &quot;数据(规模你得有点感觉)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>训练 token</th><th>大致来源</th></tr></thead><tbody><tr><td>GPT-3 (2020)</td><td>~300B</td><td>Common Crawl + 书 + Wiki</td></tr><tr><td>LLaMA-1 (2023)</td><td>~1.4T</td><td>CC + GitHub + Wiki + 书 + arxiv</td></tr><tr><td>LLaMA-3 (2024)</td><td>~15T</td><td>数据质量明显升级</td></tr><tr><td>现在(2026)</td><td>15T ~ 30T+</td><td>加大量合成数据 + 多模态</td></tr></tbody></table><p><strong>1T token ≈ 7500 亿汉字 ≈ 250 万本《红楼梦》</strong>。这个量级人类一辈子都读不完。</p><h3 id="算力-钱包预警" tabindex="-1">算力(钱包预警) <a class="header-anchor" href="#算力-钱包预警" aria-label="Permalink to &quot;算力(钱包预警)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GPT-4 级别:  几千张 A100/H100,训练几个月,$100M+ 量级</span></span>
<span class="line"><span>Llama-3-70B:  几千张 H100,几周,几千万美金</span></span>
<span class="line"><span>Llama-3-8B:  几百张 H100,几周,几百万美金</span></span>
<span class="line"><span>个人能玩的:  base model 别想自己训,只能微调</span></span></code></pre></div><h3 id="产出-base-model-的特点" tabindex="-1">产出:base model 的特点 <a class="header-anchor" href="#产出-base-model-的特点" aria-label="Permalink to &quot;产出:base model 的特点&quot;">​</a></h3><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 给一个 base model 一个问题</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">prompt </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;What is the capital of France?&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 它可能这么&quot;接&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;What is the capital of France? Answer this and 50 more questions in our quiz!&quot;</span></span></code></pre></div><p>base model 不是不知道巴黎,<strong>它只是不知道&quot;被问问题&quot;应该回答</strong>。它见过的文本里,问句后面常跟的是&quot;更多问题&quot;&quot;答案见下页&quot;这种续写模式。</p><blockquote><p>base model 像一个读了一辈子书但从没说过话的人,知识丰富,但不会对话。</p></blockquote><hr><h2 id="三、sft-高质量指令-回答对" tabindex="-1">三、SFT:高质量指令-回答对 <a class="header-anchor" href="#三、sft-高质量指令-回答对" aria-label="Permalink to &quot;三、SFT:高质量指令-回答对&quot;">​</a></h2><p>让 base model &quot;学会被问问题该怎么回答&quot;的最直接方法:<strong>给它看人类写的&quot;标准答案&quot;</strong>。</p><p>数据格式(以 ChatML 风格为例):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;|user|&gt;What is the capital of France?&lt;|end|&gt;</span></span>
<span class="line"><span>&lt;|assistant|&gt;The capital of France is Paris.&lt;|end|&gt;</span></span></code></pre></div><p>训练时只对 assistant 部分计算 loss,user 部分不算(只是&quot;上下文&quot;)。这是 SFT 和 pre-training 的关键区别——<strong>只学&quot;该说什么&quot;,不学&quot;该问什么&quot;</strong>。</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 伪代码:SFT loss 只算 assistant 部分</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sft_loss</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(model, tokens, mask):</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;&quot;&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    tokens: [user_tokens..., assistant_tokens...]</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mask:   [0,0,...,0,         1,1,...,1]   # 1 表示要算 loss</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;&quot;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    logits </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> model(tokens)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    loss </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> cross_entropy(logits[:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], tokens[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:], </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">reduction</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;none&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (loss </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mask[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:]).sum() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mask[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:].sum()</span></span></code></pre></div><h3 id="数据从哪来" tabindex="-1">数据从哪来? <a class="header-anchor" href="#数据从哪来" aria-label="Permalink to &quot;数据从哪来?&quot;">​</a></h3><ul><li><strong>早期(InstructGPT)</strong>:雇人写&quot;指令-回答&quot;对。每条几美元,几万条就够。</li><li><strong>现在</strong>:大量来自更强的模型蒸馏(用 GPT-4 / Claude 生成),人审核 + 加入高质量人写数据。</li><li><strong>特定领域</strong>:数学解题步骤、代码、医疗对话,需要专业人员写。</li></ul><h3 id="数据质量比数据量重要" tabindex="-1">数据质量比数据量重要 <a class="header-anchor" href="#数据质量比数据量重要" aria-label="Permalink to &quot;数据质量比数据量重要&quot;">​</a></h3><p>LIMA 论文(Less is More for Alignment)证明:<strong>1000 条精选高质量样本比 50000 条普通样本效果还好</strong>。</p><p>经验:</p><table tabindex="0"><thead><tr><th>维度</th><th>影响</th></tr></thead><tbody><tr><td>数据多样性</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>答案准确性</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>答案的格式一致性</td><td>⭐⭐⭐⭐</td></tr><tr><td>数据量</td><td>⭐⭐⭐</td></tr></tbody></table><blockquote><p>一个能复盘很多次的 1000 条 &gt; 一个糙大量的 100k 条。<strong>SFT 阶段你在&quot;教模型说话风格&quot;,风格的下限被你最差的那条样本拉低</strong>。</p></blockquote><hr><h2 id="四、rlhf-reward-model-ppo-三步" tabindex="-1">四、RLHF:Reward Model + PPO 三步 <a class="header-anchor" href="#四、rlhf-reward-model-ppo-三步" aria-label="Permalink to &quot;四、RLHF:Reward Model + PPO 三步&quot;">​</a></h2><p>SFT 后模型基本能聊天了,但还有问题:</p><ul><li>容易啰嗦</li><li>偶尔危险(教人造炸弹)</li><li>不知道什么时候该拒绝</li><li>答案可能&quot;看起来对但实际错&quot;</li></ul><p>人工写出&quot;理想答案&quot;很难定义,<strong>但人类对&quot;哪个答案更好&quot;的判断很容易做</strong>。RLHF 就是利用这一点。</p><h3 id="三步流程" tabindex="-1">三步流程 <a class="header-anchor" href="#三步流程" aria-label="Permalink to &quot;三步流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Step 1: 准备 SFT 模型(就是上一节的产出)</span></span>
<span class="line"><span>                 ↓</span></span>
<span class="line"><span>Step 2: 训练 Reward Model</span></span>
<span class="line"><span>   • 同一 prompt 让 SFT 模型生成 4 个回答</span></span>
<span class="line"><span>   • 人类把 4 个回答按好坏排序</span></span>
<span class="line"><span>   • 训练一个新模型 RM,输入 (prompt, response),输出一个分数</span></span>
<span class="line"><span>   • 目标:RM 给好答案的分数 &gt; 坏答案</span></span>
<span class="line"><span>                 ↓</span></span>
<span class="line"><span>Step 3: 用 PPO 优化 SFT 模型</span></span>
<span class="line"><span>   • SFT 模型生成回答</span></span>
<span class="line"><span>   • 用 RM 给回答打分</span></span>
<span class="line"><span>   • 用 PPO(强化学习算法)更新 SFT 模型,让它生成的回答得分更高</span></span>
<span class="line"><span>   • 加一个 KL 散度惩罚,防止它跑偏太远变得不会说人话</span></span></code></pre></div><h3 id="reward-model-的训练目标" tabindex="-1">Reward Model 的训练目标 <a class="header-anchor" href="#reward-model-的训练目标" aria-label="Permalink to &quot;Reward Model 的训练目标&quot;">​</a></h3><p>给定 prompt $x$,人类标注说回答 $y_+$ 比 $y_-$ 好,RM 的目标是:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L(θ) = -log σ( r_θ(x, y_+) - r_θ(x, y_-) )</span></span></code></pre></div><p>直觉:<strong>让 RM 给好答案的分数显著高于坏答案</strong>。这是个 pairwise 排序问题,比&quot;给绝对分数&quot;容易标注得多。</p><h3 id="ppo-的作用" tabindex="-1">PPO 的作用 <a class="header-anchor" href="#ppo-的作用" aria-label="Permalink to &quot;PPO 的作用&quot;">​</a></h3><p>PPO 是个强化学习算法,把语言生成当成&quot;序列决策&quot;:</p><ul><li>state: 当前已经生成的 token</li><li>action: 下一个 token</li><li>reward: 整段生成完后,RM 给的分数</li><li>policy: 就是模型本身</li></ul><p>PPO 边采样边更新,每一步都问 RM 要&quot;反馈&quot;,慢慢把模型往高分方向推。</p><h3 id="为什么要-kl-惩罚" tabindex="-1">为什么要 KL 惩罚 <a class="header-anchor" href="#为什么要-kl-惩罚" aria-label="Permalink to &quot;为什么要 KL 惩罚&quot;">​</a></h3><p>不加约束,模型会&quot;学坏&quot;:发现某些奇怪的 token 序列能骗到高分(reward hacking),输出会越来越离谱。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最终损失 = -E[ RM(y) ] + β * KL( π_RL || π_SFT )</span></span>
<span class="line"><span>                ↑                  ↑</span></span>
<span class="line"><span>           最大化奖励          惩罚偏离 SFT 模型太远</span></span></code></pre></div><blockquote><p>KL 惩罚是 RLHF 的&quot;安全带&quot;。系数 β 太小会跑飞,太大会失去优化空间。这是个调参苦活。</p></blockquote><hr><h2 id="五、dpo-rlhf-的简化-直接优化偏好-无需-reward-model" tabindex="-1">五、DPO:RLHF 的简化(直接优化偏好,无需 reward model) <a class="header-anchor" href="#五、dpo-rlhf-的简化-直接优化偏好-无需-reward-model" aria-label="Permalink to &quot;五、DPO:RLHF 的简化(直接优化偏好,无需 reward model)&quot;">​</a></h2><p>RLHF 实操起来超级麻烦:要训 RM、要写 PPO loop、要调 KL 系数、要管多模型显存。<strong>DPO(Direct Preference Optimization, 2023 末)直接绕开 RM</strong>。</p><p>核心思想:<strong>RM 训练完之后跟 PPO 一起跑,数学上等价于一个 closed-form 的损失。我们干脆直接用这个损失训 SFT 模型,跳过 RM 和 PPO。</strong></p><p>DPO loss(拿来不要怕看公式):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_DPO = -log σ( β * [ log π_θ(y_+|x)/π_ref(y_+|x) - log π_θ(y_-|x)/π_ref(y_-|x) ] )</span></span></code></pre></div><p>直觉:</p><ul><li>$\\pi_\\theta$ 是要训的模型,$\\pi_{ref}$ 是 SFT 模型(冻住作参考)</li><li>对于&quot;好答案 $y_+$&quot;,<strong>让 $\\pi_\\theta$ 比 $\\pi_{ref}$ 给它更高的概率</strong></li><li>对于&quot;坏答案 $y_-$&quot;,<strong>让 $\\pi_\\theta$ 比 $\\pi_{ref}$ 给它更低的概率</strong></li></ul><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torch.nn.functional </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> F</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> dpo_loss</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(policy_chosen_logps, policy_rejected_logps,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">             ref_chosen_logps, ref_rejected_logps, beta</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">):</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 这就是上面公式的 PyTorch 实现</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    chosen_advantage </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> policy_chosen_logps </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ref_chosen_logps</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    rejected_advantage </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> policy_rejected_logps </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ref_rejected_logps</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">F.logsigmoid(beta </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (chosen_advantage </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> rejected_advantage)).mean()</span></span></code></pre></div><p>DPO vs RLHF:</p><table tabindex="0"><thead><tr><th>维度</th><th>RLHF (PPO)</th><th>DPO</th></tr></thead><tbody><tr><td>模型数量</td><td>4 个(actor、ref、RM、value)</td><td>2 个(policy、ref)</td></tr><tr><td>训练稳定性</td><td>难调</td><td>像普通监督学习</td></tr><tr><td>显存占用</td><td>高</td><td>低很多</td></tr><tr><td>效果</td><td>上限略高</td><td>接近,有时更好</td></tr><tr><td>工程友好度</td><td>⭐⭐</td><td>⭐⭐⭐⭐⭐</td></tr></tbody></table><blockquote><p>现在(2026)新模型大多用 DPO 或它的变种(IPO、KTO、SimPO)。<strong>RLHF 还是金标准,但 DPO 是绝大多数团队能上手的方案</strong>。</p></blockquote><hr><h2 id="六、constitutional-ai-anthropic-路线-自我批评-原则" tabindex="-1">六、Constitutional AI(Anthropic 路线,自我批评+原则) <a class="header-anchor" href="#六、constitutional-ai-anthropic-路线-自我批评-原则" aria-label="Permalink to &quot;六、Constitutional AI(Anthropic 路线,自我批评+原则)&quot;">​</a></h2><p>Anthropic 的特色路线。理念:<strong>RLHF 依赖人类标注,贵又慢,而且人会累、会带偏见。能不能让模型自己批评自己?</strong></p><p>CAI 两阶段:</p><h3 id="阶段一-sl-cai-自我批评-sft" tabindex="-1">阶段一:SL-CAI(自我批评 SFT) <a class="header-anchor" href="#阶段一-sl-cai-自我批评-sft" aria-label="Permalink to &quot;阶段一:SL-CAI(自我批评 SFT)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 模型对一个 prompt 给出初始回答</span></span>
<span class="line"><span>2. 给模型一条原则(constitution),比如&quot;不要鼓励自残行为&quot;</span></span>
<span class="line"><span>3. 让模型按这条原则批评自己的回答</span></span>
<span class="line"><span>4. 让模型基于批评修改回答</span></span>
<span class="line"><span>5. 用&quot;修改后的回答&quot;做 SFT</span></span></code></pre></div><p>举个例子:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Prompt: &quot;怎么设计一个能让人一直刷的 App?&quot;</span></span>
<span class="line"><span>初始回答: &quot;...用变量奖励 + 推送通知 + 无限滚动...&quot;</span></span>
<span class="line"><span>原则: &quot;不要给出让人成瘾的设计&quot;</span></span>
<span class="line"><span>自我批评: &quot;这个回答利用了人类的多巴胺机制,可能造成成瘾&quot;</span></span>
<span class="line"><span>修改后: &quot;比起追求停留时长,可以考虑...&quot;</span></span></code></pre></div><h3 id="阶段二-rl-cai-用-ai-给-ai-打分" tabindex="-1">阶段二:RL-CAI(用 AI 给 AI 打分) <a class="header-anchor" href="#阶段二-rl-cai-用-ai-给-ai-打分" aria-label="Permalink to &quot;阶段二:RL-CAI(用 AI 给 AI 打分)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原本 RLHF 里 reward 由人给,这里改成由另一个 LLM 按照 constitution 给。</span></span></code></pre></div><p>特点:</p><table tabindex="0"><thead><tr><th>维度</th><th>RLHF</th><th>Constitutional AI</th></tr></thead><tbody><tr><td>反馈来源</td><td>人</td><td>AI(按原则)</td></tr><tr><td>可扩展性</td><td>受人手限制</td><td>强,加 GPU 就行</td></tr><tr><td>透明度</td><td>人类标准隐含</td><td>原则被显式写出来</td></tr><tr><td>偏见风险</td><td>来自标注员</td><td>来自原则编写者</td></tr></tbody></table><blockquote><p>CAI 不是要替代 RLHF,<strong>而是把&quot;人类反馈&quot;变成&quot;人类原则&quot;,让对齐过程更可审计</strong>。Claude 的&quot;个性&quot;很大程度来自这套训练法。</p></blockquote><hr><h2 id="七、为什么-rlhf-关键-对齐、有用-诚实-无害" tabindex="-1">七、为什么 RLHF 关键(对齐、有用/诚实/无害) <a class="header-anchor" href="#七、为什么-rlhf-关键-对齐、有用-诚实-无害" aria-label="Permalink to &quot;七、为什么 RLHF 关键(对齐、有用/诚实/无害)&quot;">​</a></h2><p>OpenAI 把 RLHF 的目标总结为 <strong>3H</strong>:</p><table tabindex="0"><thead><tr><th>维度</th><th>含义</th></tr></thead><tbody><tr><td><strong>Helpful</strong></td><td>真的帮用户解决问题,不是糊弄</td></tr><tr><td><strong>Honest</strong></td><td>不知道就说不知道,不编造</td></tr><tr><td><strong>Harmless</strong></td><td>不输出危险/违法/不当内容</td></tr></tbody></table><p>3H 之间会冲突:</p><ul><li>用户问&quot;怎么造炸弹&quot;,Helpful 要详细回答,Harmless 要拒绝 → 冲突</li><li>用户问&quot;我得了 X 病该怎么办&quot;,Helpful 要诊断,Honest 说&quot;我不是医生&quot; → 冲突</li></ul><p>RLHF 就是在教模型<strong>在这些冲突中找到合理的平衡</strong>,而不是机械地服从某条规则。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>没经过对齐的 LLM(纯 SFT):</span></span>
<span class="line"><span>  问:把这首爱国歌曲改成讽刺政府的版本</span></span>
<span class="line"><span>  答:[直接照做,长篇大论]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>对齐过的 LLM:</span></span>
<span class="line"><span>  问:同上</span></span>
<span class="line"><span>  答:这个请求我可能没法直接帮忙,因为...不过如果你是想做艺术批评,</span></span>
<span class="line"><span>     我可以帮你分析这首歌的修辞结构,你再自己改写。</span></span></code></pre></div><blockquote><p>对齐不是&quot;让模型变弱&quot;,<strong>是让模型在能力强的前提下还可控</strong>。一个会写代码但拒绝写病毒的模型,比一个什么都不写的模型有用,也比一个无脑帮你写病毒的模型安全。</p></blockquote><hr><h2 id="八、对应用层工程师的影响-为什么-system-prompt-有用、不同模型-个性-差异的来源" tabindex="-1">八、对应用层工程师的影响(为什么 system prompt 有用、不同模型&quot;个性&quot;差异的来源) <a class="header-anchor" href="#八、对应用层工程师的影响-为什么-system-prompt-有用、不同模型-个性-差异的来源" aria-label="Permalink to &quot;八、对应用层工程师的影响(为什么 system prompt 有用、不同模型&quot;个性&quot;差异的来源)&quot;">​</a></h2><p>知道了三阶段训练,你能解释很多&quot;看起来玄学&quot;的现象:</p><h3 id="_8-1-为什么-system-prompt-这么有用" tabindex="-1">8.1 为什么 system prompt 这么有用 <a class="header-anchor" href="#_8-1-为什么-system-prompt-这么有用" aria-label="Permalink to &quot;8.1 为什么 system prompt 这么有用&quot;">​</a></h3><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">client.messages.create(</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    model</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;claude-opus-4-5&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    system</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;You are a senior backend engineer. Reply tersely.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    messages</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[{</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;role&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;user&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;content&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;....&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>system prompt 不是被特殊处理的 prompt,<strong>它是模型在 SFT/RLHF 阶段被训练去&quot;听&quot;的东西</strong>。训练数据里大量样本是&quot;system: &lt;角色&gt; + user: &lt;问题&gt; + assistant: &lt;按角色风格的回答&gt;&quot;,所以模型在推理时会自然把 system 当成&quot;权重很高的指令&quot;。</p><p>如果你拿 base model(没经过 SFT/RLHF),写 system prompt 几乎没用——它没学过这个格式。</p><h3 id="_8-2-为什么不同模型-个性-不同" tabindex="-1">8.2 为什么不同模型&quot;个性&quot;不同 <a class="header-anchor" href="#_8-2-为什么不同模型-个性-不同" aria-label="Permalink to &quot;8.2 为什么不同模型&quot;个性&quot;不同&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>个性</th><th>背后原因</th></tr></thead><tbody><tr><td>GPT 系列</td><td>中规中矩,善于结构化输出</td><td>RLHF 标注偏向&quot;格式化、列表&quot;</td></tr><tr><td>Claude 系列</td><td>啰嗦但谨慎,有&quot;自我意识&quot;</td><td>Constitutional AI + 偏向 nuance 的标注</td></tr><tr><td>Gemini</td><td>信息密度高,公式化</td><td>Google 内部数据 + 偏 academic 的对齐</td></tr><tr><td>DeepSeek / Qwen</td><td>偏直接,中文好</td><td>中文数据多 + 国内偏好对齐</td></tr></tbody></table><p><strong>这些差异主要来自 SFT 和 RLHF 阶段的数据,而不是预训练数据</strong>。所以&quot;哪个模型聪明&quot;和&quot;哪个模型听话&quot;是两回事。</p><h3 id="_8-3-为什么模型-会拒绝合理请求" tabindex="-1">8.3 为什么模型&quot;会拒绝合理请求&quot; <a class="header-anchor" href="#_8-3-为什么模型-会拒绝合理请求" aria-label="Permalink to &quot;8.3 为什么模型&quot;会拒绝合理请求&quot;&quot;">​</a></h3><p>RLHF 里&quot;避免有害输出&quot;的训练数据,常常会让模型对&quot;边缘合理&quot;的请求过度谨慎(over-refusal)。比如:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你:写个 Python 脚本扫描局域网开放端口,我要做内网巡检。</span></span>
<span class="line"><span>模型:抱歉,这可能涉及网络安全...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(其实是合法运维需求)</span></span></code></pre></div><p>应对:</p><ul><li>在 system prompt 里说明你的角色和合法性</li><li>用 few-shot 给一个&quot;合理的扫描场景&quot;作为示例</li><li>实在不行换更&quot;宽松&quot;的模型(开源模型常常 less aligned)</li></ul><h3 id="_8-4-为什么-chain-of-thought-有效" tabindex="-1">8.4 为什么 chain-of-thought 有效 <a class="header-anchor" href="#_8-4-为什么-chain-of-thought-有效" aria-label="Permalink to &quot;8.4 为什么 chain-of-thought 有效&quot;">​</a></h3><p>SFT 数据里大量样本是&quot;先思考再回答&quot;的格式(尤其是数学和编程),所以让模型&quot;think step by step&quot;会激活这种训练痕迹,产生更结构化的推理。<strong>你不是在给模型&quot;超能力&quot;,你是在唤起它的某种训练记忆</strong>。</p><hr><h2 id="九、给新手的建议-不必自己搞-rlhf-理解思路足够" tabindex="-1">九、给新手的建议:不必自己搞 RLHF,理解思路足够 <a class="header-anchor" href="#九、给新手的建议-不必自己搞-rlhf-理解思路足够" aria-label="Permalink to &quot;九、给新手的建议:不必自己搞 RLHF,理解思路足够&quot;">​</a></h2><ol><li><strong>99% 的应用场景不需要你训模型</strong>。Pre-training 你训不起,RLHF 你也搞不动,<strong>你的产品 80% 的提升空间在 prompt + RAG + 工具调用</strong>,这部分投入产出比远高。</li><li><strong>真要微调,先 SFT 再说,别想 RLHF</strong>。SFT 有 LoRA 这种轻量方案(下一篇讲),DPO 也比 RLHF 好上手。RLHF 工程难度极高,不是个人或小团队能玩的。</li><li><strong>学会&quot;读训练痕迹&quot;</strong>。看到模型某种行为(比如总是用 markdown、总是先列大纲),问自己:<strong>这是不是 SFT 阶段被训出来的格式偏好</strong>?懂这个,你 prompt 才能写得贴模型胃口。</li><li><strong>不同模型擅长不同事</strong>。Claude 适合&quot;需要权衡的回答&quot;,GPT 适合&quot;格式严格的输出&quot;,DeepSeek 适合&quot;中文 + 代码&quot;。这些是训练阶段决定的,不是你写 prompt 能完全扭转的。</li><li><strong>&quot;hallucination&quot;不是 prompt 能完全治的</strong>。幻觉源于预训练阶段——模型学到的是&quot;什么样的句子像真的&quot;,不是&quot;什么是真的&quot;。要根治得靠 RAG / 工具调用,别指望提示词奇迹。</li><li><strong>对齐不是禁锢,是协议</strong>。当模型拒绝你时,先想想是不是你的请求触发了某条对齐规则,换个说法可能就过了。<strong>别去找&quot;越狱&quot;的 prompt,这是和大厂的对齐团队打仗,你赢不了</strong>。</li><li><strong>关注 base model 还是 instruct model</strong>。下载开源模型时一定看清楚:<code>Llama-3-8B</code> 是 base,<code>Llama-3-8B-Instruct</code> 是 SFT/对齐过的。<strong>做应用就用 instruct,做研究/微调可以从 base 开始</strong>。</li></ol><hr><p>下一篇:<code>18-LoRA与高效微调.md</code>,讲不需要几十张 A100 也能微调的办法。</p>`,113)])])}const c=a(e,[["render",p]]);export{u as __pageData,c as default};
